import UIKit
import Security
import CommonCrypto

class CryptoWallet {
    init() {
        if privateKey == nil {
            generateKeyPair()
        }
    }

    private var privateKey: SecKey?
    private var publicKey: SecKey?

    private func generateKeyPair() {
        let attributes: [String: Any] = [
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits as String: 256
        ]
        
        SecKeyGeneratePair(attributes as CFDictionary, &publicKey, &privateKey)
    }

    func signTransaction(transactionData: Data) -> Data? {
        guard let privateKey = privateKey else { return nil }
        var error: Unmanaged<CFError>?
        let signedData = SecKeyCreateSignature(privateKey,
                                               .ecdsaSignatureMessageX962SHA256,
                                               transactionData as CFData,
                                               &error) as Data?
        if let error = error {
            print("Error signing transaction: \(error.takeRetainedValue())")
        }
        return signedData
    }

    func sendTransaction(to address: String, amount: Double) {
        let transactionData = prepareTransactionData(to: address, amount: amount)
        guard let signature = signTransaction(transactionData: transactionData) else { return }
        
        let transactionDictionary = ["txData": transactionData.base64EncodedString(),
                                     "signature": signature.base64EncodedString()]
        
        var request = URLRequest(url: URL(string: "https://blockchain-api.example.com/sendTransaction")!)
        request.httpMethod = "POST"
        request.httpBody = try? JSONSerialization.data(withJSONObject: transactionDictionary, options: [])

        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if error != nil {
                print("Failed to send transaction: \(error!.localizedDescription)")
            } else {
                print("Transaction sent successfully")
            }
        }
        task.resume()
    }

    private func prepareTransactionData(to address: String, amount: Double) -> Data {
        let transactionDetails: [String: Any] = ["to": address, "amount": amount]
        let transactionData = try! JSONSerialization.data(withJSONObject: transactionDetails, options: [])
        return transactionData
    }
}

